<?php
namespace App\Modules\Hr\Advance\Actions;
use App\Modules\Hr\Advance\Enums\AdvanceStatus; use App\Modules\Hr\Advance\Enums\AdvanceTransactionType; use App\Modules\Hr\Advance\Models\HrAdvance; use App\Modules\Hr\Advance\Models\HrAdvanceTransaction; use App\Modules\Hr\Core\Services\HrAuditService; use App\Modules\Hr\Core\Services\TenantContext; use Illuminate\Support\Facades\DB; use Illuminate\Support\Str;
class PayAdvanceAction { public function __construct(private HrAuditService $audit){} public function execute(HrAdvance $advance,string $reference,?string $sourceKey=null):HrAdvance{abort_unless(auth()->user()?->hasHrPermission('hr.advances.approve'),403);abort_unless($advance->legal_entity_id===app(TenantContext::class)->getId(),404);abort_if(blank($reference),422);$sourceKey??=(string)Str::uuid();abort_unless(Str::isUuid($sourceKey),422);return DB::transaction(function()use($advance,$reference,$sourceKey){$row=HrAdvance::withoutGlobalScope('tenant')->whereKey($advance->id)->lockForUpdate()->firstOrFail();$payload=['advance_id'=>$row->id,'type'=>'disbursement','amount'=>(string)$row->requested_amount,'reference'=>trim($reference)];$hash=hash('sha256',json_encode($payload,JSON_UNESCAPED_UNICODE));$existing=HrAdvanceTransaction::withoutGlobalScope('tenant')->where('legal_entity_id',$row->legal_entity_id)->where('source_key',$sourceKey)->first();if($existing){abort_unless(hash_equals($existing->payload_hash,$hash),409,'Kaynak anahtarı farklı ödeme içeriğiyle kullanılamaz.');return $row->fresh();}abort_unless($row->status===AdvanceStatus::Approved,422,'Yalnızca onaylanmış avans ödenebilir.');HrAdvanceTransaction::create(['legal_entity_id'=>$row->legal_entity_id,'advance_id'=>$row->id,'type'=>AdvanceTransactionType::Disbursement,'amount'=>$row->requested_amount,'transaction_date'=>today(),'reference'=>trim($reference),'source_key'=>$sourceKey,'payload_hash'=>$hash,'created_by'=>auth()->id(),'created_at'=>now()]);$row->update(['status'=>AdvanceStatus::Paid,'paid_by'=>auth()->id(),'paid_at'=>now(),'payment_reference'=>trim($reference)]);$this->audit->log('advance_paid',$row,null,['reference'=>trim($reference)]);return $row->fresh();});} }
